import cn from 'clsx';
import React from 'react';

function Emphasis(props) {
  var children = props.children,
      className = props.className,
      style = props.style;
  return React.createElement("em", {
    className: cn('yozora-emphasis', className),
    style: style
  }, children);
}

Emphasis.displayName = 'YozoraEmphasis';
export { Emphasis, Emphasis as default };